import React, { useState, useEffect, useRef } from 'react';

const formatMoney = (amount) => `₹${amount.toLocaleString('en-IN')}`;
const randomBetween = (min, max) => Math.floor(Math.random() * (max - min + 1)) + min;

// Function to generate the badge value so we get fresh randoms every time
const scamBlueprints = [
  { type: "UPI Fraud", city: "Mumbai", state: "MH", badgeFn: () => formatMoney(randomBetween(5000, 50000)), color: "red" },
  { type: "Fake KYC", city: "Delhi", state: "DL", badgeFn: () => "Account Block", color: "yellow" },
  { type: "OTP Fraud", city: "Pune", state: "MH", badgeFn: () => formatMoney(randomBetween(3000, 30000)), color: "red" },
  { type: "Job Scam", city: "Bangalore", state: "KA", badgeFn: () => "₹2,500 Fee", color: "yellow" },
  { type: "Fake Police", city: "Lucknow", state: "UP", badgeFn: () => formatMoney(randomBetween(10000, 200000)), color: "red" },
  { type: "Phishing Link", city: "Chennai", state: "TN", badgeFn: () => "Link Blocked", color: "green" },
  { type: "Loan App Scam", city: "Hyderabad", state: "TS", badgeFn: () => formatMoney(randomBetween(8000, 75000)), color: "red" },
  { type: "Sextortion", city: "Jaipur", state: "RJ", badgeFn: () => formatMoney(randomBetween(20000, 500000)), color: "red" },
  { type: "Lottery Scam", city: "Kolkata", state: "WB", badgeFn: () => "₹50,000", color: "red" },
  { type: "Fake KYC", city: "Ahmedabad", state: "GJ", badgeFn: () => "OTP Leaked", color: "yellow" },
];

const getBadgeClasses = (color) => {
  switch(color) {
    case 'red': return "text-red-400 bg-red-400/10 border-red-400/20";
    case 'green': return "text-green-400 bg-green-400/10 border-green-400/20";
    case 'yellow':
    default: return "text-yellow-400 bg-yellow-400/10 border-yellow-400/20";
  }
};

const getNextRandomScam = (lastType) => {
  // Filter out the last type to ensure no consecutive duplicates
  const available = scamBlueprints.filter(s => s.type !== lastType);
  const picked = available[Math.floor(Math.random() * available.length)];
  return {
    id: Date.now() + Math.random(),
    type: picked.type,
    location: `${picked.city}, ${picked.state}`,
    time: "Just now",
    amount: picked.badgeFn(),
    badgeColor: picked.color
  };
};

// Generate initial list, making sure there are no consecutive duplicates
const generateInitialFeed = () => {
  const feed = [];
  let lastType = null;
  for (let i = 0; i < 5; i++) {
    const item = getNextRandomScam(lastType);
    item.time = i === 0 ? "Just now" : `${i * 2 + 1} mins ago`;
    feed.push(item);
    lastType = item.type;
  }
  return feed;
};

export default function ScamFeed() {
  const [feed, setFeed] = useState([]);
  const lastTypeRef = useRef(null);

  useEffect(() => {
    // Generate initial feed on mount to shuffle
    const initial = generateInitialFeed();
    setFeed(initial);
    lastTypeRef.current = initial[0].type;

    const interval = setInterval(() => {
      const newItem = getNextRandomScam(lastTypeRef.current);
      lastTypeRef.current = newItem.type;

      setFeed(prev => {
        const newFeed = [newItem, ...prev].slice(0, 10);
        return newFeed.map((item, idx) => {
           if (idx === 0) return item;
           // Simply increment time for older items to simulate feed scrolling
           return { ...item, time: `${idx * 2 + 1} mins ago` };
        });
      });
    }, 3000);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="bg-white/[0.02] backdrop-blur-xl border border-white/5 rounded-[2rem] p-6 h-[500px] flex flex-col shadow-2xl">
      <div className="flex items-center justify-between mb-6 px-2">
        <h2 className="text-xl font-black text-white flex items-center gap-3 tracking-tight">
          <span className="relative flex h-3 w-3">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.8)]"></span>
          </span>
          Live Scam Feed
        </h2>
        <span className="bg-red-500/10 text-red-500 px-3 py-1 rounded-full text-[10px] font-black tracking-widest uppercase border border-red-500/20 shadow-[0_0_10px_rgba(239,68,68,0.1)]">
          LIVE
        </span>
      </div>
      
      <div className="flex-1 overflow-y-auto pr-2 space-y-4" style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}>
        {feed.map((item) => (
          <div key={item.id} className="bg-[#0a0a0a] border border-white/5 p-4 rounded-xl hover:border-white/10 transition-all duration-300 transform shadow-inner animate-[fadeIn_0.5s_ease-out]">
            <div className="flex justify-between items-start mb-2">
              <h3 className="font-bold text-gray-200 text-sm tracking-wide">{item.type}</h3>
              <span className="text-xs text-gray-500 font-medium">{item.time}</span>
            </div>
            <div className="flex justify-between items-end mt-4">
               <p className="text-[10px] uppercase tracking-widest text-gray-400 flex items-center gap-1.5 font-bold">
                 <svg className="w-3.5 h-3.5 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                 {item.location}
               </p>
               <p className={`text-[10px] font-black tracking-wider uppercase px-2 py-1 rounded-md border ${getBadgeClasses(item.badgeColor)}`}>
                 {item.amount}
               </p>
            </div>
          </div>
        ))}
      </div>
      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(-10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
}
